package main

import (
	"database/sql"
	"fmt"
	_ "github.com/lib/pq"
)

func main() {
	// Connect to the database
	db, err := sql.Open("postgres", "host=localhost port=5432 user=postgres password=DemoPass123 dbname=demo_db sslmode=disable")
	if err != nil {
		fmt.Println(err)
	}
	defer db.Close()

	// Check connection
	err = db.Ping()
	if err != nil {
		fmt.Println(err)
	}

	// Query the database
	rows, err := db.Query("SELECT * FROM users")
	if err != nil {
		fmt.Println(err)
	}
	defer rows.Close()

	// Iterate through the results
	for rows.Next() {
		var name string
		var age int
		err = rows.Scan(&name, &age)
		if err != nil {
			fmt.Println(err)
		}
		fmt.Printf("%s is %d years old\n", name, age)
	}
}